select count(distinct anonymous_id) as activeCount
from (
    select anonymous_id from content where date(create_time) = #{today}
    union distinct
    select anonymous_id from comment where date(create_time) = #{today}
    union distinct
    select anonymous_id from `like` where date(create_time) = #{today}
    union distinct
    select anonymous_id from user_behavior where date(create_time) = #{today}
) as active_users
